                  <FilePlus size={32} />
                </div>
              </div>

              <div className="relative flex-1">
                <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-3 group-hover:text-emerald-700 dark:group-hover:text-emerald-400 transition-colors">نوی پروجکټ جوړ کړئ</h2>
                <p className="text-slate-500 dark:text-slate-400 leading-relaxed mb-8 transition-colors">
                  له پیله کار پیل کړئ. سیستم به تاسو سره د ښوونکو، ټولګیو او ساعتونو په ترتیب کې مرسته وکړي.
                </p>
              </div>

              <div className="relative mt-auto flex items-center justify-between">
                <div className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400 font-bold">
                  <span>اوس یې پیل کړئ</span>
                  <ArrowRight size={20} className="rotate-180 group-hover:-translate-x-1 transition-transform" />
