                  <FolderOpen size={32} />
                </div>
              </div>

              <div className="relative flex-1">
                <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-3 group-hover:text-indigo-700 dark:group-hover:text-indigo-400 transition-colors">پخوانی فایل خلاص کړئ</h2>
                <p className="text-slate-500 dark:text-slate-400 leading-relaxed mb-8 transition-colors">
                  که تاسو مخکې شاتړ (Backup) اخیستی وي، دلته یې بار کړئ ترڅو خپل کار ته دوام ورکړئ.
                </p>
              </div>

              <div className="relative mt-auto flex items-center justify-between">
                <div className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400 font-bold">
